import sys
def count_digits(n):
    return 1 if n==0 else len(str(n))
def is_armstrong(n):
    d=count_digits(n)
    return sum(int(ch)**d for ch in str(n))==n
def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    t=int(data[0])
    out=[]
    for i in range(1,t+1):
        n=int(data[i])
        out.append('YES' if is_armstrong(n) else 'NO')
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    main()

