const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=parseInt(input[idx++],10);
let results=[];
function countDigits(n){return n===0?1:String(n).length;}
function intPower(base,exp){let res=1;for(let i=0;i<exp;i++)res*=base;return res;}
for(let t=0;t<T;t++){
  const N=parseInt(input[idx++],10);
  const d=countDigits(N);
  let sum=0;
  let temp=N;
  while(temp>0){
    const digit=temp%10;
    sum+=intPower(digit,d);
    temp=Math.floor(temp/10);
  }
  if(N===0) sum=0;
  results.push(sum===N?'YES':'NO');
}
